(async () => {
  if (!game.user.isGM) { ui.notifications.warn("BR2: Phase 2 pressure clock is GM-only."); return; }

  const FLAG_NS  = "blooming-rot-2";
  const CLOCK_KEY = "p2-pressure-clock";
  const TILE_FLAG = "p2-clock-tile";
  const MOD_PATH  = "modules/blooming-rot-2/assets/ui";
  const SEG = 6;

  if (!game.settings.settings.has(`${FLAG_NS}.${CLOCK_KEY}`)) {
    game.settings.register(FLAG_NS, CLOCK_KEY, {
      scope: "world", config: false, type: Number, default: 0
    });
  }

  const TELEGRAPHS = [
    { name: "CLEAR",         sub: "Phase 2 \u00b7 Loftwick \u2014 no pressure." },
    { name: "TAMPERING",     sub: "Someone was looking." },
    { name: "WARNING",       sub: "Trina won\u2019t budge." },
    { name: "RUMOUR",        sub: "The party is recognisable." },
    { name: "WITNESS LOSS",  sub: "Cut the thread that hurts most." },
    { name: "MOTION FILED",  sub: "48 hours remain." },
    { name: "DOOR SHUTS",    sub: "GM\u2019s choice \u2014 the worst." },
  ];

  // Colour the counter based on urgency
  function counterColor(n) {
    if (n === 0)        return "#7a9a6e";
    if (n <= 2)         return "#c09428";
    if (n <= 4)         return "#c84040";
    return "#9b1212";
  }

  // ── tile helpers ───────────────────────────────────────────────────────────
  function findClockTile() {
    if (!canvas.scene) return null;
    return canvas.tiles.placeables.find(
      t => t.document.getFlag(FLAG_NS, TILE_FLAG) === true
    );
  }

  async function ensureClockTile(state) {
    if (!canvas.scene) return null;
    const src  = `${MOD_PATH}/pressure-clock-phase2-${state}.png`;
    let tile = findClockTile();
    if (tile) {
      await tile.document.update({ "texture.src": src });
    } else {
      const w  = 315;   // 210px * 1.5 — readable on a typical map
      const h  = 378;   // 252px * 1.5
      const px = Math.max(0, canvas.scene.width  - w - 60);
      const py = 60;
      const [doc] = await canvas.scene.createEmbeddedDocuments("Tile", [{
        x: px, y: py, width: w, height: h,
        "texture.src": src,
        overhead: true,
        occlusion: { mode: 0 },
        flags: { [FLAG_NS]: { [TILE_FLAG]: true } }
      }]);
      tile = canvas.tiles.get(doc.id);
    }
    return tile;
  }

  async function setClockState(n) {
    n = Math.max(0, Math.min(SEG, n));
    await game.settings.set(FLAG_NS, CLOCK_KEY, n);
    await ensureClockTile(n);
    return n;
  }

  // ── dialog HTML ─────────────────────────────────────────────────────────────
  function buildHtml(state) {
    const t   = TELEGRAPHS[state];
    const src = `${MOD_PATH}/pressure-clock-phase2-${state}.png`;
    return `
<div id="br2-clock-wrap"
  style="display:flex;flex-direction:column;align-items:center;gap:10px;padding:10px 0;">

  <img id="br2-clock-img"
       src="${src}"
       style="width:210px;height:252px;image-rendering:pixelated;"
       alt="Pressure clock — ${state}/${SEG} segments filled"/>

  <div style="text-align:center;font-size:0.83em;color:#9b8a6c;
              letter-spacing:0.04em;max-width:220px;line-height:1.4;">
    <span id="br2-clock-sub">${t.sub}</span>
  </div>

  <div style="display:flex;gap:10px;align-items:center;margin-top:2px;">
    <button id="br2-retreat"
      ${state === 0 ? "disabled" : ""}
      style="font-size:0.95em;min-width:84px;padding:6px 12px;">
      &#9664;&nbsp;Retreat
    </button>
    <span id="br2-clock-counter"
      style="font-size:1.4em;font-weight:700;min-width:50px;text-align:center;
             color:${counterColor(state)};">
      ${state}&#x2F;${SEG}
    </span>
    <button id="br2-advance"
      ${state === SEG ? "disabled" : ""}
      style="font-size:0.95em;min-width:84px;padding:6px 12px;">
      Advance&nbsp;&#9654;
    </button>
  </div>

  <hr style="width:80%;border:none;border-top:1px solid #5a4a30;margin:4px 0;"/>

  <button id="br2-remove-tile"
    style="font-size:0.78em;color:#888;background:none;border:none;
           text-decoration:underline;cursor:pointer;padding:0;">
    Remove tile from current scene
  </button>

</div>`;
  }

  // ── wire up the dialog ────────────────────────────────────────────────────
  let state = game.settings.get(FLAG_NS, CLOCK_KEY) ?? 0;

  // Place / update tile immediately on open
  await ensureClockTile(state);

  const dlg = new Dialog({
    title: `BR2 \u2014 Phase 2 Pressure Clock (${state}/${SEG})`,
    content: buildHtml(state),
    buttons: { close: { label: "Close" } },
    default: "close",
    render: (html) => {
      async function update(newState) {
        state = await setClockState(newState);
        html.find("#br2-clock-img").attr("src", `${MOD_PATH}/pressure-clock-phase2-${state}.png`);
        html.find("#br2-clock-sub").text(TELEGRAPHS[state].sub);
        html.find("#br2-clock-counter")
          .text(`${state}/${SEG}`)
          .css("color", counterColor(state));
        html.find("#br2-advance").prop("disabled", state === SEG);
        html.find("#br2-retreat").prop("disabled", state === 0);
        dlg.element?.find(".window-title").text(
          `BR2 \u2014 Phase 2 Pressure Clock (${state}/${SEG})`);
      }
      html.find("#br2-advance").on("click",      () => update(state + 1));
      html.find("#br2-retreat").on("click",      () => update(state - 1));
      html.find("#br2-remove-tile").on("click", async () => {
        const tile = findClockTile();
        if (tile) {
          await canvas.scene.deleteEmbeddedDocuments("Tile", [tile.id]);
          ui.notifications.info("BR2: Pressure clock tile removed from scene.");
        } else {
          ui.notifications.warn("BR2: No clock tile found on this scene.");
        }
      });
    }
  }, { width: 310 });

  dlg.render(true);
})();
